LocalizationManager:add_localized_strings({
    --intro
    ["corp_intro_01_01"] = "Итак, Вернон. Джемма сказала, что у тебя отличный техасский акцент. Очень хотелось бы его услышать.",
    ["corp_intro_01_02"] = "О нет, нет, нет. Никогда больше. Это ужасный акцент, поверь мне.",
    ["corp_intro_01_03"] = "Ну, раз так, поверю на слово.",
    ["corp_intro_02_01"] = "Ты - один из крупнейших контрабандистов в Техасе. Если не секрет, почему решил переключиться на нефть именно сейчас?",
    ["corp_intro_02_02"] = "Когда родилась моя внучка, я тщательно всё обдумал. Я зарабатываю много денег, но это грязные деньги. Трудно оставить грязные деньги в завещании. Наверное, я делаю это ради неё.",
    ["corp_intro_02_03"] = "Я бы сказал, что это чертовски веская причина. И мы рады помочь.",
    ["corp_intro_03_01"] = "Слушай, я только за здоровую конкуренцию, но Рейни перешла все границы. Взрывает мои грузовики. Наняла этого Эстебана, чтобы тот мешал моей работе. С меня хватит.",
    ["corp_intro_03_02"] = "Эта Рейни, похоже, действительно на тебя нацелилась. Это что-то личное?",
    ["corp_intro_03_03"] = "Она так делает с каждым новичком. Придавливать мелких — вот как Рейни держится на плаву. Пора бы ей отведать собственного лекарства.",

["kee_corp_01_01"] = "И убедитесь, что осмотрели Исполнительный офис. Я слышал, что Рейни записывает каждую свою встречу там. Ведь это отлично работает для политиков и подобных людей.",
["kee_corp_01_02"] = "Не забудьте осмотреть Исполнительный офис. В таком грязном деле, как у Рейни, всегда можно найти компромат.",
["kee_corp_01_03"] = "Я уверен, что вы что-то найдёте в Исполнительном офисе. Рейни умная, но и самонадеянная. Самонадеянность плюс ум = по-настоящему глупо.",
["kee_corp_02A_01"] = "Эй, смотри! Похоже, Рейни использовала средства компании, чтобы подкупить людей из EPA. Уверен, что ФБР заинтересуется этим письмом от её бухгалтера.",
["kee_corp_02B_01"] = "Вот это да. В этом письме Рейни заплатила парням из Overkill MC, чтобы те уничтожили один из моих грузовиков. Заплатила им деньгами SERA. Жду, когда пресса об этом узнает.",
["kee_corp_02_01"] = "Ну что ж, взгляните-ка! Рейни подменила деньги через своего бухгалтера, используя книги учёта SERA. Было бы обидно, если это письмо утечёт акционерам. Реальная беда.",
["kee_corp_03_01"] = "Вы также можете «уговорить» девушку из маркетинга, чтобы она сама открыла кейс. Поняли, о чём я?",
["kee_corp_03_02"] = "Или, можно попросить ведущего маркетинга ввести код. Так будет проще, согласны?",
["kee_corp_03_03"] = "И я уверен, что ведущий маркетинга сам откроет кейс, если попросите его по-хорошему.",
["kee_corp_04_01"] = "Как только закончим здесь, у меня будет всё, что нужно, чтобы запатентовать Neo-2 как изобретение Keegan Oil. Это даст мне преимущество на годы вперёд.",
["kee_corp_04_02"] = "Рейни бы завысила цену на это дело. Мир будет в лучшем положении, если купит это у меня.",
["kee_corp_04_03"] = "Когда я передам это как своё изобретение, я изменю название. Keegan-2! Keegan-o-Rama! Эй, пусть маркетологи этим занимаются.",
["kee_corp_05_01"] = "Как приятно видеть, как вы уничтожаете дорогие игрушки Рейни.",
["kee_corp_05_02"] = "Ты прекрасно освоил саботаж! Хех, понял, что я сделал?",
["kee_corp_05_03"] = "Будь тщателен. Если что-то может сломаться, сломай это до конца.",
["kee_corp_06_01"] = "Ееееехаааа!",
["kee_corp_06_02"] = "Ееееее!",
["kee_corp_06_03"] = "Ееееееееуууу!",
["kee_corp_07_01"] = "Убедитесь, что проверили Исполнительный офис. Я слышал, что Рейни записывает все её встречи. Она такая параноидальная.",
["kee_corp_07_02"] = "Мне сказали, что Рейни записывает все её встречи. Проверьте Исполнительный офис, посмотрите, правда ли это.",
["kee_corp_07_03"] = "Бьюсь об заклад, что вы найдёте что-то интересное в Исполнительном офисе.",
["kee_corp_08_01"] = "Ну разве не красавица? Она будет в каждой нефтехимической компании, на каждом заводе. Это изменит правила игры, и Keegan Oil станет лидером в этой сфере.",
["kee_corp_08_02"] = "Когда я выпущу эту штуку на рынок, а Рейни будет смотреть, как я собираю деньги... Ха! Я просто не могу остановиться от счастья.",
["kee_corp_08_03"] = "Эта штука выведет Keegan Oil на карту! Мы могли бы даже получить Нобелевскую премию. Хотел всегда съездить в Швецию. Говорят, у них очень вкусные фрикадельки.",
["kee_corp_09_01"] = "Ах, я понимаю, что ты замышляешь! Немного повреждения от воды сильно поможет!",
["kee_corp_09_02"] = "Ты собираешься затопить это место?! Джемма говорила, что вы с ума сошли. Мне это нравится!",
["kee_corp_09_03"] = "Хех, это будет весело. Отличная идея, Вернон.",
["loc_corp_01_01"] = "У нас впереди большая работа, и она начинается в главном офисе. Давайте заходим.",
["loc_corp_01_02"] = "Давайте зайдём в главный офис. Работали когда-нибудь в офисе? Дерьмо какое-то, если честно.",
["loc_corp_01_03"] = "Главное офисное здание - наша первая цель. Должно быть несложно проникнуть.",
["loc_corp_02_01"] = "Давайте двигаемся, ребята. В этом здании полно входов.",
["loc_corp_02_02"] = "Двери не закрыты, друзья. Добирайтесь до офисов.",
["loc_corp_02_03"] = "Идите в офисное здание. Keegan не платит нам по часам.",
["loc_corp_03_01"] = "Пора искать компромат на Элис Рейни. Осмотрите офис, ищите письма, голосовые сообщения, что угодно, что может её уличить.",
["loc_corp_03_02"] = "Поиск в офисе: письма, голосовые сообщения и всё, что может показать истинное лицо Элис Рейни.",
["loc_corp_03_03"] = "Если на Рейни есть что-то грязное, лучший шанс найти это в офисах на втором этаже. Голосовые сообщения, письма - должно быть что-то.",
["loc_corp_04_01"] = "Как идёт поиск? Не забывайте проверять и частные офисы.",
["loc_corp_04_02"] = "Может, что-то интересное найдёте в одном из частных офисов.",
["loc_corp_04_03"] = "Один из частных офисов принадлежит главному охраннику. Бьюсь об заклад, что он знает какие-то гадости.",
["loc_corp_05_01"] = "Как идёт поиск? Не забывайте проверять Исполнительный офис Рейни.",
["loc_corp_05_02"] = "Не забудьте заглянуть в Исполнительный офис.",
["loc_corp_05_03"] = "Бьюсь об заклад, что в Исполнительном офисе Рейни найдётся интересная информация.",
["loc_corp_06_01"] = "Как идёт поиск? Не пропустите офисные кубики.",
["loc_corp_06_02"] = "Не игнорируйте офисные кубики. Там могут быть интересные вещи на тех компьютерах.",
["loc_corp_06_03"] = "Не забывайте проверять офисные кубики.",
["loc_corp_07_01"] = "Хорошо, друзья. SERA готовится представить их прототип по улавливанию углерода в зале мероприятий. Посмотрите.",
["loc_corp_07_02"] = "Отлично. SERA переместила их прототип по улавливанию углерода в зал мероприятий. Пойдите посмотрите.",
["loc_corp_07_03"] = "Теперь идите в зал мероприятий SERA. Прототип по улавливанию углерода должен быть там для сегодняшнего мероприятия.",
["loc_corp_08_01"] = "Зал мероприятий находится на нижнем этаже офисного здания. Пойдите проверьте.",
["loc_corp_08_02"] = "Зал мероприятий внизу, друзья.",
["loc_corp_08_03"] = "Офисное здание, первый этаж. Давайте, именно там вы найдёте зал мероприятий.",
["loc_corp_09_01"] = "Нео-2 в этом витрине, прямо на виду. Посмотри, сможешь ли опустить занавески, чтобы нам было чуть уютнее.",
["loc_corp_09_02"] = "Они уже поставили Нео-2 на сцену, под ярким прожектором. Его будет проще украсть, если сначала опустишь занавески.",
["loc_corp_09_03"] = "Вот он, Нео-2 на сцене. Мы не сможем вынести его отсюда, пока эти занавески подняты.",
["loc_corp_10_01"] = "Поищи за кулисами способ опустить занавески.",
["loc_corp_10_02"] = "Ставлю, что управление занавесками где-то за кулисами.",
["loc_corp_10_03"] = "Пойди за кулисы и найди управление занавесками.",
["loc_corp_11_01"] = "Этот брелок помечен как \"Сценические занавески\". Может, пригодится.",
["loc_corp_11_02"] = "Этот ключ открывает управление сценическими занавесками. Думаю, он нам понадобится.",
["loc_corp_11_03"] = "Ключ от управления занавесками на сцене? Отличная находка.",
["loc_corp_12_01"] = "Пульт управления занавесами надёжно заперт. Это явно не связано с безопасностью. Может, на стойке регистрации есть ключ?",
["loc_corp_12_02"] = "Они поставили замок на управление занавесками? Это чересчур! Проверь ресепшн на наличие ключа.",
["loc_corp_12_03"] = "Думаю, ключ от управления занавесками можно найти на ресепшн. Это не то, чем обычно занимается охрана.",
["loc_corp_13_01"] = "Витрина с прототипом заперта с помощью клавиатуры. Руководитель отдела маркетинга SERA отвечает за всё это. Загляни в её офис за кодом.",
["loc_corp_13_02"] = "Если нам нужен код от витрины Нео-2, стоит проверить офис руководителя отдела маркетинга. Она отвечает за это событие.",
["loc_corp_13_03"] = "Мы всего в одном коде от того, чтобы украсть Нео-2. Говорят, руководитель отдела маркетинга SERA должен записать его у себя в офисе.",
["loc_corp_14_01"] = "Проверь офис руководителя отдела маркетинга за кодом или возьми её в заложники и заставь открыть витрину.",
["loc_corp_14_02"] = "Получите код из её офиса или заставьте её открыть витрину. Как вам удобнее.",
["loc_corp_14_03"] = "Два способа получить этот код. Возьмите руководителя отдела маркетинга в заложники или поищите в её офисе.",
["loc_corp_15_01"] = "Это, должно быть, код для витрины Нео-2! Возвращайся туда и вводи его.",
["loc_corp_15_02"] = "Ты нашел код для витрины! Теперь мы можем взять Нео-2.",
["loc_corp_15_03"] = "Вот! Это код для Нео-2.",
["loc_corp_16_01"] = "Посмотри на этот номерной знак! Думаю, это машина маркетолога. Если немного поцарапаешь её, сигнализация приведет её наружу.",
["loc_corp_16_02"] = "Наши данные говорят, что эта машина принадлежит руководителю маркетинга. Если ты хочешь её вывести наружу, эта сигнализация сделает своё дело.",
["loc_corp_16_03"] = "Я бы поставил деньги, что это машина маркетолога. Наверняка она прибежит, если сигнализация сработает. За размышления.",
["loc_corp_17_01"] = "Думаю, она готова сотрудничать! Отведи её обратно к витрине и постарайся не привлекать внимания.",
["loc_corp_17_02"] = "Отведи её обратно к витрине Нео-2. Думаю, она не настолько безумна, чтобы умереть ради какой-то глупой нефтяной компании.",
["loc_corp_17_03"] = "Будь осторожен, возвращая её на сцену. Если кто-то увидит оружие, они сразу же поднимут тревогу.",
["loc_corp_18_01"] = "Отлично, друзья! Закрепите Нео-2, чтобы мы могли продать его Кигану. Вон там стоит фургон на парковке.",
["loc_corp_18_02"] = "Отличная работа! Принеси прототип к нашему фургону на парковке. Мы этого заслужили.",
["loc_corp_18_03"] = "Загрузите Нео-2 в наш фургон для побега. Кто нашёл, тот и забрал, да?",
["loc_corp_19_01"] = "Мы получили прототип, но нам ещё нужны данные о его работе. Найди путь в офисы Исследовательского центра.",
["loc_corp_19_02"] = "Следующий шаг - направляемся в Исследовательский центр. Нужно собрать все документы, связанные с Нео-2.",
["loc_corp_19_03"] = "Все документы по Нео-2 находятся в Исследовательском центре. Нам нужно забрать их.",
["loc_corp_20_01"] = "Исследовательский центр должен быть прямо напротив главного офисного здания.",
["loc_corp_20_02"] = "Не должно быть сложно найти Исследовательский центр. Он прямо напротив главного офисного здания.",
["loc_corp_20_03"] = "Есть два входа в подземное помещение. Ищи тот, который помечен как Исследовательский центр.",
["loc_corp_21_01"] = "Документы, которые нам нужны, находятся в комнате хранения документов, но эти двери гораздо тяжелее, чем мы ожидали. У Главного научного сотрудника, наверное, есть доступ. Найди его.",
["loc_corp_21_02"] = "У них стоят довольно тяжёлые двери в комнате хранения документов, так что нам нужен доступ для их открытия. Поищи у Главного научного сотрудника.",
["loc_corp_21_03"] = "Данные по Нео-2 заперты в комнате хранения документов. Найди Главного научного сотрудника, у него должен быть доступ.",
["loc_corp_22_01"] = "Нужно найти Главного научного сотрудника. Проверь его офис, а если его там нет, ищи его расписание.",
["loc_corp_22_02"] = "Если Главного научного сотрудника нет в офисе, проверь его расписание.",
["loc_corp_22_03"] = "Главный научный сотрудник точно должен быть на месте для большого события. Может, в его офисе есть расписание.",
["loc_corp_23_01"] = "Вот расписание Главного научного сотрудника. Теперь мы можем отслеживать его передвижения.",
["loc_corp_23_02"] = "Это расписание поможет нам найти Главного научного сотрудника.",
["loc_corp_23_03"] = "Дневник Главного научного сотрудника! То, что нам нужно.",
["loc_corp_24_01"] = "Этот пропуск ведет в хранилище НИОКР. Держи его.",
["loc_corp_24_02"] = "С этим пропуском мы можем попасть в хранилище документов.",
["loc_corp_24_03"] = "Не встречал пропусков, которые бы не пригодились!",
["loc_corp_25_01"] = "Все исследования по Нео-2 хранятся в этой комнате. Найди, что нам нужно, и забери.",
["loc_corp_25_02"] = "Ищи все документы по Нео-2. Нам нельзя оставлять ничего позади.",
["loc_corp_25_03"] = "Все данные по Нео-2 сохранены здесь. Забери их.",
["loc_corp_26_01"] = "Прототип ценен только в том случае, если SERA не сможет построить новый. Пойдем в лабораторию, посмотрим, что можно поломать.",
["loc_corp_26_02"] = "Нужно убедиться, что SERA не сможет восстановить Нео-2. Пора ломать оборудование в лаборатории.",
["loc_corp_26_03"] = "Нам нужно найти лабораторию и разрушить её. Киган не сможет запатентовать Нео-2, если SERA создаст новый первым.",
["loc_corp_27_01"] = "Давай, не тормози. Лаборатория в крыле напротив исследовательских офисов.",
["loc_corp_27_02"] = "Лабораторию найдешь на другой стороне исследовательского комплекса.",
["loc_corp_27_03"] = "Иди в крыло напротив исследовательских офисов. Там будет лаборатория.",
["loc_corp_28_01"] = "Будет трудно разрушить лабораторию, если все эти ученые будут рядом. Подключись к системе оповещения в административном здании, я смогу выманить их наружу.",
["loc_corp_28_02"] = "Если мы начнем ломать оборудование сейчас, эти ученые сразу поднимут тревогу. Нам нужно их вывезти. Найди систему оповещения на верхнем этаже.",
["loc_corp_28_03"] = "Конечно, эти лабораторные крысы работают допоздна. Должна быть система оповещения в административном здании. Давай использовать её, чтобы выгнать их.",
["loc_corp_29_01"] = "Это выглядит как система оповещения для всего кампуса! Может, сможем использовать её, чтобы выманить ученых из лаборатории.",
["loc_corp_29_02"] = "Мы можем использовать эту систему оповещения, чтобы привлечь ученых из лаборатории.",
["loc_corp_29_03"] = "Вот она, система оповещения кампуса. Я могу выманить ученых из лаборатории, если ты подключишь меня.",
["loc_corp_30_01"] = "Давайте поздравим с днем рождения...Кита! Все знают Кита! В его честь мы подаем торт на веранде! Спешите, пока его не съел! Кит съест его весь, если мы не помешаем!",
["loc_corp_30_02"] = "В честь Национального дня науки мы раздаем бесплатные тако всем ученым! Они вкусные! Лучшая еда, или я не...Деннис? Точно. Я Деннис, и я одобряю эти тако. Они снаружи. Сейчас.",
["loc_corp_30_03"] = "Чрезвычайная ситуация! В лаборатории утечка газа! Это плохо, друзья. Так, как будто кожа слезает, а легкие лопаются. Но не переживайте, это всего лишь тренировка. Или все-таки нет. Хотите остаться и узнать?",
["loc_corp_31_01"] = "Давайте разгрузим немного пара в этих чертовых лабораторных приборах! Ломаем всё!",
["loc_corp_31_02"] = "Лаборатория теперь наша, ребята! Оставим её хуже, чем нашли!",
["loc_corp_31_03"] = "Разрушьте лабораторию, друзья! Делайте, что хотите!",
["loc_corp_32_01"] = "Отличная работа по саботажу, друзья! Мы закончили. Давайте уходить!",
["loc_corp_32_02"] = "Хватит с нас корпоративного шпионажа на сегодня! Время уходить.",
["loc_corp_32_03"] = "Чёрт возьми, молодцы! Наши дела завершены. Давайте уходим.",
